$ErrorActionPreference = "Stop"
$Host.UI.RawUI.WindowTitle = "GY-NEXUS 한국형 쇼츠 스튜디오 적용"

$scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$candidates = @(
    $scriptDir,
    (Split-Path -Parent $scriptDir),
    (Get-Location).Path
) | Select-Object -Unique

$projectRoot = $null
foreach ($candidate in $candidates) {
    if ($candidate -and (Test-Path (Join-Path $candidate "package.json"))) {
        $projectRoot = (Resolve-Path $candidate).Path
        break
    }
}

if (-not $projectRoot) {
    Write-Host ""
    Write-Host "오류: GY-NEXUS 프로젝트 폴더를 찾지 못했습니다." -ForegroundColor Red
    Write-Host "이 압축 폴더를 GY-NEXUS 프로젝트 안에 넣은 뒤 다시 실행하세요." -ForegroundColor Yellow
    exit 1
}

Set-Location $projectRoot
$stamp = Get-Date -Format "yyyyMMdd-HHmmss"
$backupRoot = Join-Path $projectRoot ".gy-backups\korean-shorts-studio-$stamp"

$files = [ordered]@{
    ".gitignore" = "bm9kZV9tb2R1bGVzLwoubmV4dC8Kb3V0LwouZW52Ci5lbnYubG9jYWwKLmVudi4qLmxvY2FsCioubG9nCi5EU19TdG9yZQoudmVyY2VsLwpjb3ZlcmFnZS8KLmd5LWJhY2t1cHMvCg=="
    "lib\korean-shorts\types.ts" = ""
    "lib\korean-shorts\fallback.ts" = ""
    "app\api\korean-shorts\generate\route.ts" = ""
    "app\admin\korean-shorts\page.tsx" = ""
    "components\korean-shorts\KoreanShortsStudio.tsx" = ""
    "components\korean-shorts\KoreanShortsStudio.module.css" = ""
    "components\admin\AdminSidebar.tsx" = ""
    "components\admin\AdminMobileDock.tsx" = ""
    "app\admin\mobile-auto-shorts\page.tsx" = "aW1wb3J0IHsgcmVkaXJlY3QgfSBmcm9tICJuZXh0L25hdmlnYXRpb24iOwoKZXhwb3J0IGRlZmF1bHQgZnVuY3Rpb24gTW9iaWxlQXV0b1Nob3J0c1BhZ2UoKSB7CiAgcmVkaXJlY3QoIi9hZG1pbi9rb3JlYW4tc2hvcnRzIik7Cn0K"
    "app\admin\revenue-shorts\page.tsx" = ""
}

Write-Host ""
Write-Host "==========================================================" -ForegroundColor DarkCyan
Write-Host " GY-NEXUS 한국형 쇼츠 스튜디오 V1 적용" -ForegroundColor Cyan
Write-Host "==========================================================" -ForegroundColor DarkCyan
Write-Host "프로젝트: $projectRoot" -ForegroundColor White
Write-Host ""
Write-Host "중국 쇼핑 숏폼 제작실은 그대로 보존합니다." -ForegroundColor Green
Write-Host "한국형 쇼츠 스튜디오를 별도 메뉴로 추가합니다." -ForegroundColor Green
Write-Host "중복 메뉴는 사이드바에서 통합하고 기존 주소는 안전하게 연결합니다." -ForegroundColor Green
Write-Host ""

# 이전 패치의 임시 TSX 폴더가 남아 있으면 Next.js가 검사하므로 제거합니다.
$oldPatch = Join-Path $projectRoot "PATCH"
if (Test-Path $oldPatch) {
    Remove-Item -Recurse -Force $oldPatch
    Write-Host "정리: 이전 임시 PATCH 폴더 삭제" -ForegroundColor Yellow
}

$records = @()
try {
    foreach ($entry in $files.GetEnumerator()) {
        $relative = $entry.Key
        $target = Join-Path $projectRoot $relative
        $existed = Test-Path $target
        $backup = Join-Path $backupRoot $relative

        if ($existed) {
            New-Item -ItemType Directory -Force -Path (Split-Path -Parent $backup) | Out-Null
            Copy-Item $target $backup -Force
        }

        New-Item -ItemType Directory -Force -Path (Split-Path -Parent $target) | Out-Null
        [System.IO.File]::WriteAllBytes(
            $target,
            [System.Convert]::FromBase64String([string]$entry.Value)
        )

        $records += [pscustomobject]@{
            Relative = $relative
            Target = $target
            Backup = $backup
            Existed = $existed
        }
        Write-Host "적용: $relative" -ForegroundColor Green
    }

    $nextFolder = Join-Path $projectRoot ".next"
    if (Test-Path $nextFolder) {
        Remove-Item -Recurse -Force $nextFolder -ErrorAction SilentlyContinue
    }

    Write-Host ""
    Write-Host "프로덕션 빌드를 검증합니다..." -ForegroundColor Cyan
    Write-Host ""

    & npm.cmd run build
    $buildCode = $LASTEXITCODE
    if ($buildCode -ne 0) {
        throw "npm run build 실패 (종료 코드: $buildCode)"
    }

    Write-Host ""
    Write-Host "==========================================================" -ForegroundColor DarkGreen
    Write-Host " 적용 및 프로덕션 빌드 성공" -ForegroundColor Green
    Write-Host "==========================================================" -ForegroundColor DarkGreen
    Write-Host ""
    Write-Host "새 메뉴: /admin/korean-shorts" -ForegroundColor White
    Write-Host "중국 전용: /admin/revenue-shorts" -ForegroundColor White
    Write-Host "이전 모바일 원클릭 주소는 한국형 쇼츠로 자동 이동합니다." -ForegroundColor White
    Write-Host ""
    Write-Host "원본 백업: $backupRoot" -ForegroundColor Yellow
    Write-Host ""
    Write-Host "GitHub Desktop에서 아래 커밋 문구로 Commit 후 Push하세요." -ForegroundColor Cyan
    Write-Host "Add integrated Korean Shorts Studio" -ForegroundColor White
    Write-Host ""
    Write-Host "터미널을 선호하면:" -ForegroundColor DarkCyan
    Write-Host 'git status --short'
    Write-Host 'git add .gitignore app/admin/korean-shorts app/api/korean-shorts components/korean-shorts lib/korean-shorts components/admin/AdminSidebar.tsx components/admin/AdminMobileDock.tsx app/admin/mobile-auto-shorts/page.tsx app/admin/revenue-shorts/page.tsx'
    Write-Host 'git commit -m "Add integrated Korean Shorts Studio"'
    Write-Host 'git push'
    exit 0
}
catch {
    $reason = $_.Exception.Message
    Write-Host ""
    Write-Host "적용 또는 빌드가 실패했습니다: $reason" -ForegroundColor Red
    Write-Host "이번 패치 파일을 자동으로 원상 복구합니다." -ForegroundColor Yellow

    foreach ($record in ($records | Select-Object -Reverse)) {
        if ($record.Existed -and (Test-Path $record.Backup)) {
            New-Item -ItemType Directory -Force -Path (Split-Path -Parent $record.Target) | Out-Null
            Copy-Item $record.Backup $record.Target -Force
        } elseif (Test-Path $record.Target) {
            Remove-Item $record.Target -Force
        }
    }

    Write-Host "원상 복구 완료. 백업은 다음 위치에 남아 있습니다:" -ForegroundColor Yellow
    Write-Host $backupRoot -ForegroundColor White
    exit 1
}
